using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
        new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
        new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and fundamental forces." },
        new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
        new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events, societies, and civilizations." },
    ];

    private readonly List<Course> _courses =
    [
        new() { Id = 1, Code = "CS 101", Title = "Introduction to Programming", Description = "Learn fundamentals of programming using Python. Covers variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen holds a PhD from MIT and has 15 years of experience teaching introductory computer science. Her research focuses on CS education.", DepartmentId = 1, IsFeatured = true },
        new() { Id = 2, Code = "CS 201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (trees, graphs, hash tables) and algorithm design techniques (divide and conquer, dynamic programming).", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park specializes in algorithm optimization and competitive programming. He has authored two textbooks on algorithm design.", DepartmentId = 1, IsFeatured = true },
        new() { Id = 3, Code = "CS 310", Title = "Database Systems", Description = "Introduction to relational databases, SQL, normalization, indexing, and transaction management.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", InstructorName = "Dr. Maria Lopez", InstructorBio = "Dr. Lopez worked at Oracle for 10 years before joining academia. She specializes in distributed database systems.", DepartmentId = 1, IsFeatured = false },
        new() { Id = 4, Code = "CS 450", Title = "Machine Learning", Description = "Foundations of machine learning including supervised learning, unsupervised learning, and neural networks.", Credits = 4, Schedule = "Tue/Thu 1:00–2:20 PM", InstructorName = "Dr. Ahmed Hassan", InstructorBio = "Dr. Hassan leads the university's AI research lab and has published over 50 papers in top ML conferences.", DepartmentId = 1, IsFeatured = true },
        new() { Id = 5, Code = "MATH 101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions with applications.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Klein", InstructorBio = "Dr. Klein is an award-winning educator with 20 years of experience making calculus accessible to all students.", DepartmentId = 2, IsFeatured = true },
        new() { Id = 6, Code = "MATH 201", Title = "Linear Algebra", Description = "Vector spaces, linear transformations, matrices, determinants, and eigenvalues.", Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", InstructorName = "Dr. Emily Nguyen", InstructorBio = "Dr. Nguyen's research spans computational mathematics and numerical methods. She holds a Fields Medal nomination.", DepartmentId = 2, IsFeatured = false },
        new() { Id = 7, Code = "MATH 301", Title = "Probability & Statistics", Description = "Random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "Mon/Wed 11:00 AM–12:20 PM", InstructorName = "Dr. Robert Klein", InstructorBio = "Dr. Klein is an award-winning educator with 20 years of experience making calculus accessible to all students.", DepartmentId = 2, IsFeatured = false },
        new() { Id = 8, Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM + Lab Thu 2:00–4:50 PM", InstructorName = "Dr. Lisa Yamamoto", InstructorBio = "Dr. Yamamoto is an experimental physicist whose research on quantum optics has been featured in Nature.", DepartmentId = 3, IsFeatured = true },
        new() { Id = 9, Code = "PHYS 220", Title = "Electromagnetism", Description = "Electric and magnetic fields, Maxwell's equations, electromagnetic waves, and optics.", Credits = 4, Schedule = "Tue/Thu 11:00 AM–12:20 PM + Lab Fri 1:00–3:50 PM", InstructorName = "Dr. David Okonkwo", InstructorBio = "Dr. Okonkwo brings cutting-edge research from CERN to the classroom, specializing in particle physics and field theory.", DepartmentId = 3, IsFeatured = false },
        new() { Id = 10, Code = "ENG 101", Title = "College Writing", Description = "Develop critical reading and academic writing skills through essay composition and peer review.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Prof. Karen Mitchell", InstructorBio = "Prof. Mitchell is a published author and former journalist who emphasizes clear, compelling writing in all disciplines.", DepartmentId = 4, IsFeatured = false },
        new() { Id = 11, Code = "ENG 240", Title = "American Literature", Description = "Survey of American literary works from the colonial period to the present day.", Credits = 3, Schedule = "Tue/Thu 2:00–3:20 PM", InstructorName = "Dr. Thomas Reed", InstructorBio = "Dr. Reed is a leading scholar of 20th-century American fiction and a Pulitzer Prize jury member.", DepartmentId = 4, IsFeatured = true },
        new() { Id = 12, Code = "HIST 101", Title = "World Civilizations", Description = "Survey of major civilizations and turning points in world history from antiquity to 1500.", Credits = 3, Schedule = "Mon/Wed 3:00–4:20 PM", InstructorName = "Dr. Patricia Owens", InstructorBio = "Dr. Owens is a historian specializing in ancient Mediterranean cultures with extensive fieldwork experience.", DepartmentId = 5, IsFeatured = false },
        new() { Id = 13, Code = "HIST 250", Title = "Modern World History", Description = "Major political, social, and economic developments from the Enlightenment to the present.", Credits = 3, Schedule = "Tue/Thu 3:30–4:50 PM", InstructorName = "Dr. Michael Torres", InstructorBio = "Dr. Torres focuses on 20th-century geopolitics and has served as a consultant for several documentary films.", DepartmentId = 5, IsFeatured = true },
    ];

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }
}

