@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>@(course?.Title ?? "Course Not Found")</PageTitle>

@if (course is null)
{
    <h1>Course Not Found</h1>
    <p>The requested course does not exist.</p>
    <a href="courses" class="btn btn-secondary">Back to Catalog</a>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item active" aria-current="page">@course.Code</li>
        </ol>
    </nav>

    <h1>@course.Code — @course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h2>Description</h2>
            <p>@course.Description</p>

            <h3 class="mt-4">Schedule</h3>
            <p><strong>@course.Schedule</strong></p>

            <h3 class="mt-4">Credits</h3>
            <p><span class="badge bg-primary fs-6">@course.Credits credits</span></p>
        </div>
        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h4 class="card-title">Instructor</h4>
                    <h5>@course.InstructorName</h5>
                    <p class="card-text">@course.InstructorBio</p>
                </div>
            </div>

            <div class="mt-3">
                <a href="enroll?courseId=@course.Id" class="btn btn-success w-100">Enroll in This Course</a>
            </div>
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Course? course;

    protected override void OnInitialized()
    {
        course = Catalog.GetCourse(Id);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Submit this form to request enrollment in a course.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted</h4>
        <p>Thank you, <strong>@Model.Name</strong>. Your enrollment request for
            <strong>@selectedCourseName</strong> has been received. You will be contacted at your university email.</p>
    </div>
    <a href="enroll" class="btn btn-primary">Submit Another Request</a>
}
else
{
    <div class="row">
        <div class="col-md-6">
            <EditForm Model="Model" method="post" OnValidSubmit="HandleSubmit" FormName="enrollment">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />

                <div class="mb-3">
                    <label for="name" class="form-label">Full Name</label>
                    <InputText id="name" class="form-control" @bind-Value="Model.Name" />
                    <ValidationMessage For="() => Model.Name" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText id="studentId" class="form-control" @bind-Value="Model.StudentId" />
                    <ValidationMessage For="() => Model.StudentId" class="text-danger" />
                    <div class="form-text">6-10 alphanumeric characters (e.g., STU12345)</div>
                </div>

                <div class="mb-3">
                    <label for="course" class="form-label">Course</label>
                    <InputSelect id="course" class="form-select" @bind-Value="Model.CourseId">
                        <option value="0">— Select a course —</option>
                        @foreach (var course in courses)
                        {
                            <option value="@course.Id">@course.Code — @course.Title</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => Model.CourseId" class="text-danger" />
                </div>

                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
            </EditForm>
        </div>
    </div>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private List<Course> courses = [];
    private bool submitted;
    private string selectedCourseName = string.Empty;

    protected override void OnInitialized()
    {
        courses = Catalog.GetCourses();

        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        var course = Catalog.GetCourse(Model.CourseId);
        selectedCourseName = course is not null ? $"{course.Code} — {course.Title}" : "Unknown";
        submitted = true;
    }
}

